import json
import os
import uuid
from datetime import datetime


def lambda_handler(event, context):
    """
    AWS Lambda function that serves user data as JSON for a single-page application.
    Configured with permissive CORS headers for development flexibility.
    """
    
    # Define CORS headers - allowing requests from any origin for dev flexibility
    cors_headers = {
        "Access-Control-Allow-Origin": "*",
        "Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, OPTIONS",
        "Access-Control-Allow-Headers": "Content-Type, Authorization, X-Requested-With, X-Api-Key",
        "Access-Control-Max-Age": "86400",
        "Content-Type": "application/json"
    }
    
    # Handle preflight OPTIONS request
    http_method = event.get("httpMethod") or event.get("requestContext", {}).get("http", {}).get("method", "GET")
    
    if http_method == "OPTIONS":
        return {
            "statusCode": 200,
            "headers": cors_headers,
            "body": ""
        }
    
    # Determine the resource path
    path = event.get("path") or event.get("rawPath", "/")
    
    # Extract path parameters and query string parameters
    path_parameters = event.get("pathParameters") or {}
    query_parameters = event.get("queryStringParameters") or {}
    
    try:
        # Route handling
        if path == "/users" and http_method == "GET":
            response_body = get_users(query_parameters)
            status_code = 200
            
        elif path.startswith("/users/") and http_method == "GET":
            user_id = path_parameters.get("userId") or path.split("/")[-1]
            response_body = get_user_by_id(user_id)
            if response_body is None:
                status_code = 404
                response_body = {"error": "User not found", "userId": user_id}
            else:
                status_code = 200
                
        elif path == "/users" and http_method == "POST":
            body = json.loads(event.get("body", "{}"))
            response_body = create_user(body)
            status_code = 201
            
        elif path.startswith("/users/") and http_method == "PUT":
            user_id = path_parameters.get("userId") or path.split("/")[-1]
            body = json.loads(event.get("body", "{}"))
            response_body = update_user(user_id, body)
            if response_body is None:
                status_code = 404
                response_body = {"error": "User not found", "userId": user_id}
            else:
                status_code = 200
                
        elif path.startswith("/users/") and http_method == "DELETE":
            user_id = path_parameters.get("userId") or path.split("/")[-1]
            response_body = delete_user(user_id)
            if response_body is None:
                status_code = 404
                response_body = {"error": "User not found", "userId": user_id}
            else:
                status_code = 200
                
        elif path == "/health":
            response_body = {
                "status": "healthy",
                "timestamp": datetime.utcnow().isoformat() + "Z",
                "version": "1.0.0"
            }
            status_code = 200
            
        else:
            response_body = {
                "error": "Not Found",
                "message": f"No route matches {http_method} {path}"
            }
            status_code = 404
            
    except json.JSONDecodeError:
        status_code = 400
        response_body = {"error": "Invalid JSON in request body"}
    except ValueError as e:
        status_code = 400
        response_body = {"error": "Bad Request", "message": str(e)}
    except Exception as e:
        status_code = 500
        response_body = {"error": "Internal Server Error", "message": str(e)}
    
    return {
        "statusCode": status_code,
        "headers": cors_headers,
        "body": json.dumps(response_body, default=str)
    }


