def get_users(query_params):
    """Get all users with optional filtering and pagination."""
    users = list(MOCK_USERS.values())
    
    # Filter by role
    role_filter = query_params.get("role")
    if role_filter:
        users = [u for u in users if u["role"] == role_filter]
    
    # Filter by active status
    active_filter = query_params.get("isActive")
    if active_filter is not None:
        is_active = active_filter.lower() == "true"
        users = [u for u in users if u["isActive"] == is_active]
    
    # Search by name or email
    search = query_params.get("search", "").lower()
    if search:
        users = [
            u for u in users
            if search in u["firstName"].lower()
            or search in u["lastName"].lower()
            or search in u["email"].lower()
            or search in u["username"].lower()
        ]
    
    # Pagination
    page = int(query_params.get("page", "1"))
    page_size = int(query_params.get("pageSize", "10"))
    
    if page < 1:
        page = 1
    if page_size < 1 or page_size > 100:
        page_size = 10
    
    total = len(users)
    start = (page - 1) * page_size
    end = start + page_size
    paginated_users = users[start:end]
    
    return {
        "data": paginated_users,
        "pagination": {
            "page": page,
            "pageSize": page_size,
            "total": total,
            "totalPages": (total + page_size - 1) // page_size if total > 0 else 0
        },
        "timestamp": datetime.utcnow().isoformat() + "Z"
    }


def get_user_by_id(user_id):
    """Get a single user by ID."""
    user = MOCK_USERS.get(user_id)
    if user:
        return {"data": user, "timestamp": datetime.utcnow().isoformat() + "Z"}
    return None


def create_user(body):
    """Create a new user."""
    required_fields = ["username", "email", "firstName", "lastName"]
    for field in required_fields:
        if field not in body:
            raise ValueError(f"Missing required field: {field}")
    
    # Validate email uniqueness
    for existing_user in MOCK_USERS.values():
        if existing_user["email"] == body["email"]:
            raise ValueError(f"Email already in use: {body['email']}")
        if existing_user["username"] == body["username"]:
            raise ValueError(f"Username already taken: {body['username']}")
    
    new_id = f"usr-{uuid.uuid4().hex[:8]}"
    now = datetime.utcnow().isoformat() + "Z"
    
    new_user = {
        "id": new_id,
        "username": body["username"],
        "email": body["email"],
        "firstName": body["firstName"],
        "lastName": body["lastName"],
        "role": body.get("role", "viewer"),
        "avatar": f"https://api.dicebear.com/7.x/avataaars/svg?seed={body['username']}",
        "preferences": body.get("preferences", {
            "theme": "light",
            "language": "en",
            "notifications": True
        }),
        "createdAt": now,
        "updatedAt": now,
        "isActive": True
    }
    
    MOCK_USERS[new_id] = new_user
    
    return {
        "data": new_user,
        "message": "User created successfully",
        "timestamp": now
    }


def update_user(user_id, body):
    """Update an existing user."""
    if user_id not in MOCK_USERS:
        return None
    
    user = MOCK_USERS[user_id]
    now = datetime.utcnow().isoformat() + "Z"
    
    # Update allowed fields
    updatable_fields = ["email", "firstName", "lastName", "role", "preferences", "isActive"]
    for field in updatable_fields:
        if field in body:
            user[field] = body[field]
    
    user["updatedAt"] = now
    MOCK_USERS[user_id] = user
    
    return {
        "data": user,
        "message": "User updated successfully",
        "timestamp": now
    }


def delete_user(user_id):
    """Delete a user by ID."""
    if user_id not in MOCK_USERS:
        return None
    
    deleted_user = MOCK_USERS.pop(user_id)
    
    return {
        "data": {"id": user_id},
        "message": f"User {deleted_user['username']} deleted successfully",
        "timestamp": datetime.utcnow().isoformat() + "Z"
    }


